class Solution(object):
    def minimumSubarrayLength(self, nums, k):
        if k == 0:
            return 1
        n = len(nums)
        bit_count = [0] * 32
        ans = float('inf')
        left = 0

        def current_or():
            result = 0
            for i in range(32):
                if bit_count[i]:
                    result |= (1 << i)
            return result

        for right in range(n):
            # Add nums[right] to window
            for i in range(32):
                if nums[right] >> i & 1:
                    bit_count[i] += 1
            # Shrink from left while OR >= k
            while left <= right and current_or() >= k:
                ans = min(ans, right - left + 1)
                for i in range(32):
                    if nums[left] >> i & 1:
                        bit_count[i] -= 1
                left += 1

        return ans if ans != float('inf') else -1
